const SUPABASE_URL = 'https://hgheyqwnrcvwtgngqdnq.supabase.co';
const SB_KEY = '{{SUPABASE_SERVICE_ROLE_KEY}}';

const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(now.getDate() - 1);
yesterday.setHours(0, 0, 0, 0);
const today = new Date(now);
today.setHours(0, 0, 0, 0);

const startDate = yesterday.toISOString();
const endDate = today.toISOString();

const res = await this.helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/hvac_call_log' +
    '?call_timestamp=gte.' + startDate +
    '&call_timestamp=lt.' + endDate +
    '&select=call_id,agent_id,company_name,caller_name,caller_phone,job_type,lead_score,is_lead,is_hot_lead,urgency,caller_sentiment,summary,notes,duration_seconds,call_successful,retell_summary,retell_sentiment,transfer_attempted,emergency,call_type' +
    '&order=call_timestamp.asc',
  headers: {
    apikey: SB_KEY,
    Authorization: 'Bearer ' + SB_KEY
  },
  json: true
});

const calls = Array.isArray(res) ? res : [];
console.log('[Transcript Analysis] Found ' + calls.length + ' calls for ' + yesterday.toDateString());

if (calls.length === 0) {
  return [{ json: { no_calls: true, date: yesterday.toDateString() } }];
}

return calls.map(c => ({ json: c }));

const d = $input.item.json;

// Build analysis context from Retell built-in data + our Groq-parsed data
const transcript_text = d.retell_summary || d.summary || d.notes || '';
const call_id = d.call_id || '';

if (!call_id || transcript_text.length < 10) {
  return { json: { ...d, analysis: { skipped: true, reason: 'insufficient_data' } } };
}

const GROQ_KEY = '{{GROQ_API_KEY}}';

const systemPrompt = `You are an AI quality analyst for Syntharra — a company that runs AI phone receptionists for HVAC businesses.
Analyze this call record and return ONLY a JSON object with these fields:

{
  "quality_score": <integer 1-10, overall call quality>,
  "confusion_loops": <integer, how many times agent seemed stuck or repeated itself>,
  "frustration_detected": <boolean, caller showed frustration or asked for human>,
  "price_hallucination": <boolean, agent stated specific dollar amounts they shouldn't have>,
  "premature_ending": <boolean, call ended before info was fully captured>,
  "missed_lead": <boolean, should have been a lead but wasn't scored as one>,
  "issue_category": <string: "none" | "loop" | "wrong_transfer" | "missed_lead" | "data_gap" | "sentiment_mismatch" | "premature_end" | "hallucination">,
  "issue_description": <string, 1 sentence description of the main issue, or "No issues detected">,
  "learning_note": <string, 1 sentence actionable improvement for the agent prompt, or "None">,
  "requires_prompt_fix": <boolean, true if this reveals a systematic agent prompt problem>
}

Return ONLY the JSON object. No explanation, no markdown.`;

const userPrompt = `Call ID: ${call_id}
Company: ${d.company_name || 'Unknown'}
Job Type: ${d.job_type || 'Unknown'}
Lead Score: ${d.lead_score || 0}
Is Lead: ${d.is_lead}
Call Successful (Retell): ${d.call_successful}
Duration: ${d.duration_seconds || 0}s
Sentiment: ${d.retell_sentiment || d.caller_sentiment || 'Unknown'}
Emergency: ${d.emergency || false}
Transfer Attempted: ${d.transfer_attempted || false}

Summary: ${transcript_text}
Additional Notes: ${d.notes || 'None'}`;

try {
  const groqRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      Authorization: 'Bearer ' + GROQ_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'llama-3.3-70b-versatile',
      temperature: 0.1,
      max_tokens: 400,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    })
  });

  const raw = groqRes.choices[0].message.content.trim();
  let analysis;
  try {
    analysis = JSON.parse(raw.replace(/```json|```/g, '').trim());
  } catch(e) {
    analysis = { error: 'parse_failed', raw: raw.substring(0, 100), quality_score: 5, issue_category: 'none', issue_description: 'Parse failed', learning_note: 'None', requires_prompt_fix: false };
  }

  return { json: { ...d, analysis } };
} catch(e) {
  return { json: { ...d, analysis: { error: e.message, skipped: true, quality_score: 5, issue_category: 'none' } } };
}

const SUPABASE_URL = 'https://hgheyqwnrcvwtgngqdnq.supabase.co';
const SB_KEY = '{{SUPABASE_SERVICE_ROLE_KEY}}';
const h = { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal,resolution=ignore-duplicates' };

const items = $input.all();
let saved = 0;
let issues = [];

for (const item of items) {
  const d = item.json;
  const a = d.analysis || {};
  if (a.skipped) continue;

  const secFlags = [];
  if (a.price_hallucination) secFlags.push('price_hallucination');

  const notesParts = [
    a.issue_description || 'No issues',
    a.learning_note && a.learning_note !== 'None' ? 'FIX: ' + a.learning_note : null,
    a.missed_lead ? 'MISSED LEAD detected' : null,
    a.requires_prompt_fix ? 'PROMPT FIX required' : null
  ].filter(Boolean);

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/transcript_analysis',
      headers: h,
      body: {
        call_id: d.call_id,
        agent_id: d.agent_id,
        company_name: d.company_name,
        analysis_date: new Date().toISOString().split('T')[0],
        confusion_loops: a.confusion_loops || 0,
        frustration_detected: a.frustration_detected || false,
        price_hallucination: a.price_hallucination || false,
        premature_ending: a.premature_ending || false,
        security_flags: secFlags,
        overall_score: a.quality_score || 50,
        analysis_notes: notesParts.join(' | ')
      },
      json: true
    });
    saved++;

    if (a.requires_prompt_fix || a.frustration_detected || a.missed_lead) {
      issues.push({
        call_id: d.call_id,
        company: d.company_name,
        issue: a.issue_category,
        description: a.issue_description,
        note: a.learning_note,
        score: a.quality_score,
        requires_fix: a.requires_prompt_fix
      });
    }
  } catch(e) {
    console.error('[Save] Error on ' + d.call_id + ': ' + e.message);
  }
}

return [{ json: { saved, issues, total_analyzed: items.length } }];

// Pull today's analysis, build learning summary, push to GitHub FAILURES.md + Slack
const SUPABASE_URL = 'https://hgheyqwnrcvwtgngqdnq.supabase.co';
const SB_KEY = '{{SUPABASE_SERVICE_ROLE_KEY}}';
const GITHUB_TOKEN = '{{GITHUB_TOKEN}}';
const SLACK_WH = '{{SLACK_WEBHOOK_URL}}';

const today = new Date().toISOString().split('T')[0];

// Fetch today's analysis summary
const res = await this.helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/transcript_analysis' +
    '?analysis_date=eq.' + today +
    '&select=quality_score,issue_category,issue_description,learning_note,requires_prompt_fix,frustration_detected,missed_lead,company_name',
  headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY },
  json: true
});

const rows = Array.isArray(res) ? res : [];
if (rows.length === 0) {
  return [{ json: { status: 'no_analysis_today' } }];
}

const total = rows.length;
const avgScore = rows.reduce((s, r) => s + (r.quality_score || 5), 0) / total;
const issues = rows.filter(r => r.requires_prompt_fix);
const frustrated = rows.filter(r => r.frustration_detected);
const missed = rows.filter(r => r.missed_lead);
const byCategory = {};
rows.forEach(r => { byCategory[r.issue_category] = (byCategory[r.issue_category] || 0) + 1; });

// Build Slack digest
const scoreEmoji = avgScore >= 8 ? '🟢' : avgScore >= 6 ? '🟡' : '🔴';
const blocks = {
  text: '*Syntharra Daily Call Intelligence Report* — ' + today,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: '📊 Daily Call Intelligence — ' + today } },
    { type: 'section', text: { type: 'mrkdwn', text: scoreEmoji + ' *Agent Health Score: ' + avgScore.toFixed(1) + '/10* across ' + total + ' calls analysed' } },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: '*🔥 Issues needing fix:* ' + issues.length },
      { type: 'mrkdwn', text: '*😤 Frustrated callers:* ' + frustrated.length },
      { type: 'mrkdwn', text: '*💰 Missed leads:* ' + missed.length },
      { type: 'mrkdwn', text: '*📂 Issue breakdown:* ' + JSON.stringify(byCategory).replace(/[{}"]/g, '').replace(/,/g, ' | ') }
    ]}
  ]
};

// Add issue details if any prompt fixes needed
if (issues.length > 0) {
  const issueText = issues.slice(0, 3).map(i => '• ' + i.issue_description + ' → _' + i.learning_note + '_').join('\n');
  blocks.blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: '*🛠️ Prompt Fixes Needed:*\n' + issueText }
  });
  blocks.blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: '_I will apply these fixes at the start of the next chat session._' }
  });
}

// Post to Slack
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SLACK_WH,
    body: blocks,
    json: true
  });
} catch(e) {
  console.error('Slack failed: ' + e.message);
}

// Push learning notes to GitHub FAILURES.md if there are prompt fixes
if (issues.length > 0) {
  try {
    // Fetch current FAILURES.md
    const ghRes = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/repos/Syntharra/syntharra-automations/contents/docs/FAILURES.md',
      headers: { Authorization: 'Bearer ' + GITHUB_TOKEN, 'User-Agent': 'n8n-syntharra' },
      json: true
    });

    const currentContent = Buffer.from(ghRes.content, 'base64').toString('utf-8');
    const sha = ghRes.sha;

    // Build new rows
    const newRows = issues.map(i => 
      '| ' + today + ' | Agent Behaviour (auto-detected) | ' + i.issue_description + ' | ' +
      'Detected via daily transcript analysis — call_id: ' + i.call_id + ' | ' +
      'Queued for prompt fix: ' + i.learning_note + ' | No — queued |'
    ).join('\n');

    const updatedContent = currentContent + '\n' + newRows;
    const encoded = Buffer.from(updatedContent).toString('base64');

    await this.helpers.httpRequest({
      method: 'PUT',
      url: 'https://api.github.com/repos/Syntharra/syntharra-automations/contents/docs/FAILURES.md',
      headers: { 
        Authorization: 'Bearer ' + GITHUB_TOKEN, 
        'Content-Type': 'application/json',
        'User-Agent': 'n8n-syntharra'
      },
      body: {
        message: '[auto] Daily transcript learning — ' + today + ' (' + issues.length + ' issues)',
        content: encoded,
        sha: sha
      },
      json: true
    });
    console.log('[Learning] Pushed ' + issues.length + ' learning notes to FAILURES.md');
  } catch(e) {
    console.error('[Learning] GitHub push failed: ' + e.message);
  }
}

return [{ json: { total, avgScore: avgScore.toFixed(2), issues: issues.length, frustrated: frustrated.length, missed: missed.length, slack_sent: true } }];

